const ContactList = mirror({
  tag: 'List',
  base: {
    width: '30%',
    background: '$surface.bg',
    borderRight: '1px solid $muted.col'
  }
})

const ContactDetails = mirror({
  tag: 'Col',
  base: {
    width: '70%',
    padding: '$lg.pad',
    gap: '$md.gap'
  }
})

const App = () => (
  <Row style={{ height: 'full' }}>
    <ContactList>
      {each('$contact', '$contacts', (
        <Item 
          listItem 
          onClick={{ 
            action: 'assign', 
            variable: '$selected', 
            expression: '$contact' 
          }}
          style={{
            background: '$selected.contact.id === $contact.id ? $primary.bg : $surface.bg'
          }}
        >
          <Avatar src="$contact.avatar" />
          <Text>{'{$contact.name}'}</Text>
        </Item>
      ))}
    </ContactList>

    <ContactDetails>
      {condition('$selected', 
        <>
          <Avatar src="$selected.avatar" size="lg" />
          <Title>{'{$selected.name}'}</Title>
          <Text>{'{$selected.email}'}</Text>
          <Text>{'{$selected.phone}'}</Text>
        </>,
        <Text style={{ color: '$muted.col' }}>Select a contact</Text>
      )}
    </ContactDetails>
  </Row>
)
